<table>
<thead>
<tr>
<th>事件名称</th>
<th>描述</th>
</tr>
</thead>
<tbody>
<tr>
<td><code v-pre>usb-plug-in</code></td>
<td>USB 设备插入</td>
</tr>
<tr>
<td><code v-pre>usb-plug-out</code></td>
<td>USB 设备拔出</td>
</tr>
</tbody>
</table>
<h3 id="磁盘事件" tabindex="-1"><a class="header-anchor" href="#磁盘事件"><span>磁盘事件</span></a></h3>
<table>
