<th>事件名称</th>
<th>描述</th>
</tr>
</thead>
<tbody>
<tr>
<td><code v-pre>disk-mount</code></td>
<td>磁盘挂载</td>
</tr>
<tr>
<td><code v-pre>disk-unmount</code></td>
<td>磁盘卸载</td>
</tr>
</tbody>
</table>
